                    <button onClick={() => setQty(key, q + 1)} style={{ width: 26, height: 26, borderRadius: 4, border: "none", background: "#C41E2A", color: "#fff", cursor: "pointer", fontSize: 14, lineHeight: "24px" }}>+</button>
